CREATE TABLE client_profiles (user_id UUID PRIMARY KEY REFERENCES users(user_id) ON DELETE CASCADE, date_of_birth DATE, gender TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE restaurant_owner_profiles (user_id UUID PRIMARY KEY REFERENCES users(user_id) ON DELETE CASCADE, fssai_license_number_encrypted BYTEA, gstin_encrypted BYTEA, pan_number_encrypted BYTEA, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE driver_profiles (user_id UUID PRIMARY KEY REFERENCES users(user_id) ON DELETE CASCADE, driving_license_number_encrypted BYTEA NOT NULL, vehicle_registration_encrypted BYTEA NOT NULL, is_available BOOLEAN NOT NULL DEFAULT FALSE, current_city VARCHAR(80), created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
CREATE TABLE bank_accounts (bank_account_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), user_id UUID NOT NULL REFERENCES users(user_id) ON DELETE CASCADE, account_number_encrypted BYTEA NOT NULL, ifsc_code VARCHAR(11) NOT NULL, is_primary BOOLEAN NOT NULL DEFAULT TRUE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
